256→private fun ASTNode.replaceWhitespaceWith(text: String) {
257→    require(this.elementType == WHITE_SPACE)
258→    if (this.text != text) {
259→        (this.psi as LeafElement).rawReplaceWithText(text)
260→    }
261→}
