import com.pinterest.ktlint.rule.engine.api.Code
import com.pinterest.ktlint.rule.engine.api.KtLintRuleEngine
import com.pinterest.ktlint.rule.engine.core.api.ElementType.BLOCK
import com.pinterest.ktlint.rule.engine.core.api.ElementType.FUN
import com.pinterest.ktlint.rule.engine.core.api.ElementType.LBRACE
import com.pinterest.ktlint.rule.engine.core.api.ElementType.RPAR
import com.pinterest.ktlint.rule.engine.core.api.ElementType.VALUE_PARAMETER_LIST
import com.pinterest.ktlint.rule.engine.core.api.ElementType.WHITE_SPACE
import org.assertj.core.api.Assertions.assertThat
import org.jetbrains.kotlin.com.intellij.lang.ASTNode
import org.jetbrains.kotlin.com.intellij.lang.FileASTNode
import org.junit.jupiter.api.Test

class ASTNodeWhitespacePlacementTest {
    @Test
    fun `Given LBRACE which is first child of a BLOCK then upsertWhitespaceBeforeMe inserts whitespace before the BLOCK`() {
        val code = "fun foo(){}"

        val fileAstNode = transformCodeToAST(code)
        val funNode = requireNotNull(fileAstNode.findChildByType(FUN))
        val blockNode = requireNotNull(funNode.findChildByType(BLOCK))
        val lbraceNode = requireNotNull(blockNode.firstChildNode)
        require(lbraceNode.elementType == LBRACE)

        lbraceNode.upsertWhitespaceBeforeMe(" ")

        assertThat(fileAstNode.text).isEqualTo("fun foo() {}")
        assertThat(blockNode.firstChildNode.elementType).isEqualTo(LBRACE)
        assertThat(blockNode.treePrev.elementType).isEqualTo(WHITE_SPACE)
        assertThat(blockNode.treePrev.text).isEqualTo(" ")
    }

    @Test
    fun `Given RPAR which is last child of a VALUE_PARAMETER_LIST then upsertWhitespaceAfterMe inserts whitespace after the VALUE_PARAMETER_LIST`() {
        val code = "fun foo(){}"

        val fileAstNode = transformCodeToAST(code)
        val funNode = requireNotNull(fileAstNode.findChildByType(FUN))
        val valueParameterList = requireNotNull(funNode.findChildByType(VALUE_PARAMETER_LIST))
        val rparNode = requireNotNull(valueParameterList.findChildByType(RPAR))
        require(rparNode.treeNext == null) { "RPAR should be last child of VALUE_PARAMETER_LIST in this test" }

        rparNode.upsertWhitespaceAfterMe(" ")

        assertThat(fileAstNode.text).isEqualTo("fun foo() {}")
        assertThat(valueParameterList.treeNext.elementType).isEqualTo(WHITE_SPACE)
        assertThat(valueParameterList.treeNext.text).isEqualTo(" ")
        assertThat(valueParameterList.treeNext.treeNext.elementType).isEqualTo(BLOCK)
    }

    private fun transformCodeToAST(code: String): FileASTNode =
        KtLintRuleEngine(
            ruleProviders =
                setOf(
                    RuleProvider { DummyRule() },
                ),
        ).transformToAst(
            Code.fromSnippet(code),
        )

    /**
     * A dummy rule for testing.
     */
    private open class DummyRule : Rule(
        ruleId = RuleId("test:dummy-rule"),
        about = About(),
    ) {
        override fun beforeVisitChildNodes(
            node: ASTNode,
            autoCorrect: Boolean,
            emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
        ) {
        }
    }
}
