{"file_path":"/project/ktlint-rule-engine/src/test/kotlin/com/pinterest/ktlint/rule/engine/api/FormatWhitespaceBeforeFunctionBodyRegressionTest.kt","content":"package com.pinterest.ktlint.rule.engine.api

import com.pinterest.ktlint.rule.engine.core.api.Rule
import com.pinterest.ktlint.rule.engine.core.api.RuleId
import com.pinterest.ktlint.rule.engine.core.api.RuleProvider
import com.pinterest.ktlint.ruleset.standard.rules.FunctionSignatureRule
import com.pinterest.ktlint.ruleset.standard.rules.FunctionStartOfBodySpacingRule
import com.pinterest.ktlint.ruleset.standard.rules.SpacingAroundCurlyRule
import org.assertj.core.api.Assertions.assertThat
import org.junit.jupiter.api.Test
import java.util.concurrent.atomic.AtomicInteger

class FormatWhitespaceBeforeFunctionBodyRegressionTest {
    @Test
    fun `Format should converge within 2 runs when inserting missing whitespace before function body`() {
        val code =
            """
            class UampNotificationManager(
                private val context: Context,
                sessionToken: MediaSessionCompat.Token,
                notificationListener: PlayerNotificationManager.NotificationListener,
            ) {
                fun showNotificationForPlayer(player: Player){
                    notificationManager.setPlayer(player)
                }
            }
            """.trimIndent()

        val expected =
            """
            class UampNotificationManager(
                private val context: Context,
                sessionToken: MediaSessionCompat.Token,
                notificationListener: PlayerNotificationManager.NotificationListener,
            ) {
                fun showNotificationForPlayer(player: Player) {
                    notificationManager.setPlayer(player)
                }
            }
            """.trimIndent()

        val formatRunCounter = AtomicInteger(0)
        val ruleProviders =
            setOf(
                RuleProvider { SpacingAroundCurlyRule() },
                RuleProvider { FunctionStartOfBodySpacingRule() },
                RuleProvider { FunctionSignatureRule() },
                RuleProvider {
                    object : Rule(
                        ruleId = RuleId("test:format-run-counter"),
                        about = About(),
                    ) {
                        override fun beforeFirstNode(editorConfig: com.pinterest.ktlint.rule.engine.core.api.editorconfig.EditorConfig) {
                            formatRunCounter.incrementAndGet()
                        }
                    }
                },
            )

        val formatted =
            KtLintRuleEngine(
                ruleProviders = ruleProviders,
            ).format(
                Code.fromSnippet(code),
            )

        assertThat(formatted).isEqualTo(expected)
        assertThat(formatRunCounter.get()).isEqualTo(2)
    }
}
