328→
329→                val insertionParent = insertAfter?.treeParent
330→                if (insertionParent != null) {
331→                    insertionParent.addChild(psiWhiteSpace.node, insertAfter?.treeNext)
332→                } else if (treeParent != null) {
333→                    // Fall back to inserting in the current parent. This also prevents failures when the node is
334→                    // temporarily detached from the tree due to ongoing autocorrections.
335→                    (psi as LeafElement).rawInsertAfterMe(psiWhiteSpace)
336→                }
337→            }
338→        }
339→    } else {

339→    } else {
340→        lastChildLeafOrSelf().upsertWhitespaceAfterMe(text)
341→    }
342→}
