344→public val ASTNode.column: Int
345→    get() {
346→        var leaf = this.prevLeaf()
347→        var offsetToTheLeft = 0
348→        while (leaf != null) {
349→            if ((leaf.elementType == WHITE_SPACE || leaf.elementType == REGULAR_STRING_PART) && leaf.textContains('\n')) {
350→                offsetToTheLeft += leaf.textLength - 1 - leaf.text.lastIndexOf('\n')
351→                break
352→            }
353→            offsetToTheLeft += leaf.textLength
354→            leaf = leaf.prevLeaf()
355→        }
356→        return offsetToTheLeft + 1
357→    }
