362→public fun ASTNode.indent(includeNewline: Boolean = true): String =
363→    leaves(forward = false)
364→        .firstOrNull { it.isWhiteSpaceWithNewline() }
365→        ?.text
366→        ?.substringAfterLast('\n')
367→        .orEmpty() // Fallback if node is not preceded by any newline character
368→        .applyIf(includeNewline) { prefixIfNot("\n") }
